// ── Custom cursor ─────────────────────────────────────────────────────────────
function CustomCursor() {
  const [pos, setPos] = useState({ x: -100, y: -100 });
  const [hovered, setHovered] = useState(false);
  useEffect(() => {
    const onMove = (e) => setPos({ x: e.clientX, y: e.clientY });
    const onOver = (e) => setHovered(!!e.target.closest("a,button,[data-hover]"));
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseover", onOver);
    return () => { window.removeEventListener("mousemove", onMove); window.removeEventListener("mouseover", onOver); };
  }, []);
  return (
    <>
      <motion.div className="fixed z-[999] pointer-events-none rounded-full"
        style={{ width: 8, height: 8, background: "#C8FF00", top: 0, left: 0 }}
        animate={{ x: pos.x - 4, y: pos.y - 4, scale: hovered ? 0 : 1 }}
        transition={{ type: "spring", stiffness: 900, damping: 40, mass: 0.1 }} />
      <motion.div className="fixed z-[999] pointer-events-none rounded-full"
        style={{ width: 40, height: 40, border: "1px solid rgba(200,255,0,0.5)", top: 0, left: 0 }}
        animate={{ x: pos.x - 20, y: pos.y - 20, scale: hovered ? 2.2 : 1, borderColor: hovered ? "#C8FF00" : "rgba(200,255,0,0.4)" }}
        transition={{ type: "spring", stiffness: 200, damping: 30 }} />
    </>
  );
}

