// ── Animated counter ──────────────────────────────────────────────────────────
function Counter({ end, suffix, label }) {
  const [val, setVal] = useState(0);
  const ref = useRef(null);
  const inView = useInView(ref, { once: true });
  useEffect(() => {
    if (!inView) return;
    let v = 0;
    const inc = end / 80;
    const t = setInterval(() => {
      v += inc;
      if (v >= end) { setVal(end); clearInterval(t); } else setVal(Math.floor(v));
    }, 18);
    return () => clearInterval(t);
  }, [inView, end]);
  return (
    <div ref={ref} className="text-center group">
      <div style={{ fontFamily: "'Bebas Neue', sans-serif" }} className="text-7xl md:text-8xl text-[#C8FF00] group-hover:text-white transition-colors duration-300">
        {val}{suffix}
      </div>
      <div className="text-gray-600 text-[10px] tracking-[0.4em] uppercase mt-2">{label}</div>
    </div>
  );
}

